function addStores(n){for(var i,t=0;t<n.length;t++)i=new Option(n[t].storeName,n[t].storeId,!1,!1),$("#store-dropdown").append(i).trigger("change")}function getSubTotal(n){for(var i=0,t=0;t<n.length;t++)i+=n[t].totalCost;return i}function getShippingTotal(n){for(var i=0,t=0;t<n.length;t++)i+=n[t].shippingCost;return i}function getInvoiceData(){var t=document.getElementById("store-dropdown"),i=t.options[t.selectedIndex].value,n;console.log(i);n="/SalesReports/PullStoreSalesReports";console.log(n);console.log(moment($("#daterange").data("daterangepicker").startDate).toDate());console.log(moment($("#daterange").data("daterangepicker").endDate).toDate());$.get(n,{StoreId:i,StartDate:$("#daterange").data("daterangepicker").startDate.format("M-D-YYYY"),EndDate:$("#daterange").data("daterangepicker").endDate.format("M-D-YYYY")},function(n){var t=getSubTotal(n),i=getShippingTotal(n),r=i+t;$("#sub-total").text("$ "+formatMoney(t));$("#shipping-total").text("$ "+formatMoney(i));$("#total-cost").text("$ "+formatMoney(r));console.log(n);$("#partial-table").load("/SalesReports/PartialViewInvoice",function(){console.log("Attempted Refresh")})})}function formatMoney(n,t,i,r){t=isNaN(t=Math.abs(t))?2:t;i=typeof i=="undefined"?".":i;r=typeof r=="undefined"?",":r;var e=n<0?"-":"",f=String(parseInt(n=Math.abs(Number(n)||0).toFixed(t))),u=(u=f.length)>3?u%3:0;return e+(u?f.substr(0,u)+r:"")+f.substr(u).replace(/(\decSep{3})(?=\decSep)/g,"$1"+r)+(t?i+Math.abs(n-f).toFixed(t).slice(2):"")}